-- -- Tabel structuur voor tabel `calender_daginfo`-- DROP TABLE IF EXISTS `calender_daginfo`;CREATE TABLE IF NOT EXISTS `calender_daginfo` (  `event_id` int(11) NOT NULL auto_increment,  `mmdd` varchar(7) default NULL,  `event_naam` varchar(35) default NULL,  `event_tekst` text,  `event_url` varchar(80) default 'nog in te vullen',  `event_gewicht` smallint(4) NOT NULL default '0',  PRIMARY KEY  (`event_id`),  KEY `mmdd` (`mmdd`(6))) TYPE=MyISAM AUTO_INCREMENT=100 ;-- -- Gegevens worden uitgevoerd voor tabel `calender_daginfo`-- INSERT INTO `calender_daginfo` VALUES (1, '0713', 'de laatste heks', 'in 1782 is in het Zwitserse het kanton Glarus onthoofd: Anna G&ouml;ldi. In een geheim proces is zij (achteraf uit wraak) beschuldigd van hekserij en is, ondanks imternationaal protest ge&euml;xecuteerd. G&ouml;ldi is hiermee het laatste slachtoffer van de heksenvervolging in Europa.', '', 9);INSERT INTO `calender_daginfo` VALUES (2, '0714', 'de Bastille', 'in 1789 werd de Bastille werd bestormd... toen kwam markies de Sade uit de kast', '', 9);